SELECT count(*) FROM title, movie_companies, company_type, company_name, movie_info, cast_info, name, movie_keyword WHERE movie_companies.movie_id = title.id AND movie_companies.company_type_id = company_type.id AND movie_companies.company_id = company_name.id AND movie_info.movie_id = title.id AND cast_info.movie_id = title.id AND cast_info.person_id = name.id AND movie_keyword.movie_id = title.id;